onClick:
{{(() => {
    // Use LocationManager validation
    const validation = LocationManager.validateOrderForm();

    if (!validation.isValid) {
        showAlert("Please fix the following errors:\n" + validation.errors.join("\n"), "error");
        return;
    }

    // Validate service rate selection
    if (!OrderShippingSelect.selectedOptionValue) {
        showAlert("Please select a delivery service (Standard or Express)", "error");
        return;
    }

    // Show loading
    showAlert("Creating service quote and order...", "info");

    // Step 1: Create service quote
    CreateServiceQuoteForOrder.run()
        .then(() => {
            // Step 2: Get the created service quote
            return GetCreatedServiceQuote.run();
        })
        .then(() => {
            // Step 3: Verify service quote was retrieved
            const serviceQuote = GetCreatedServiceQuote.data?.[0];
            if (!serviceQuote?.service_quote_uuid) {
                throw new Error("Failed to create or retrieve service quote");
            }

            showAlert(`Service quote created for ${serviceQuote.service_name}. Creating order...`, "info");

            // Step 4: Create the order with service quote
            return CreateOrderAPI.run();
        })
        .then((result) => {
            const order = result.order || result;
            const orderId = order.public_id || order.id || "New Order";


            showAlert(`Order ${orderId} created successfully`,
"success");

            // Reset form using LocationManager
            LocationManager.resetOrderForm();

            closeModal('CreateOrderModal');

            // Refresh all dashboard data
            GetOrdersList.run();
            GetTotalOrders.run();
            GetOrdersByStatus.run();
            GetDailyOrders.run();
        })
        .catch(err => {
            console.error("Order creation failed:", err);
            showAlert("Error creating order: " + (err.message || "Please check your input and try again"), "error");
        });
})()}}
